// ---------- Parameterized subjects ----------

// Per-row change emitted by wal-gateway. Subject pattern is '<prefix>.<schema>.<table>.<op>'. The default prefix is 'cdc' and the default stream name is 'CDC'. Consumers usually subscribe to the prefix tail wildcard ('cdc.>').
// Service: dd-wal-gateway
const CdcRowChangePattern = "{prefix}.{schema}.{table}.{op}"
const CdcRowChangeWildcard = "{prefix}.>"
const CdcRowChangeStream = "CDC"
type CdcRowChangeSubjectParts struct {
	Prefix string
	Schema string
	Table string
	Op string
}

func CdcRowChangeSubject(prefix string, schema string, table string, op string) string {
	return fmt.Sprintf("%s.%s.%s.%s", prefix, schema, table, op)
}

func ParseCdcRowChangeSubject(subject string) (*CdcRowChangeSubjectParts, bool) {
	patternTokens := strings.Split("{prefix}.{schema}.{table}.{op}", ".")
	subjectTokens := strings.Split(subject, ".")
	if len(patternTokens) != len(subjectTokens) {
		return nil, false
	}
	parts := &CdcRowChangeSubjectParts{}
	for i, p := range patternTokens {
		s := subjectTokens[i]
		if strings.HasPrefix(p, "{") && strings.HasSuffix(p, "}") {
			name := p[1 : len(p)-1]
			switch name {
			case "prefix":
				parts.Prefix = s
			case "schema":
				parts.Schema = s
			case "table":
				parts.Table = s
			case "op":
				parts.Op = s
			default:
				return nil, false
			}
			continue
		}
		if p != s {
			return nil, false
		}
	}
	return parts, true
}

// Per-table JetStream filter subject ('<prefix>.<schema>.<table>.>') used by CDC consumers (e.g. dd-remote-rest-api) to subscribe to every op for one Postgres table. Not a publish target; producers publish per-row via CdcRowChange.
